8572	
8573	\leanok
8574	[Sections of one push--pull leg over an open]
8575	  \label{lem:pushPull_leg_sections}
8576	  \lean{AlgebraicGeometry.pushPull_leg_sections}
8577	  \uses{def:push_pull_obj, def:cech_free_presheaf_complex, lem:pushforward_obj_obj_mathlib,
8578	    lem:restrictFunctorIsoPullback_mathlib, lem:restrict_obj_mathlib}
8579	  Let \(j_\sigma : U_\sigma \hookrightarrow X\) be the open immersion of the intersection
8580	  open \(U_\sigma = \operatorname{coverInterOpen}\mathcal{U}\,\sigma\), and let
8581	  \(V \subseteq X\) be an open. Then there is a natural isomorphism of section groups
8582	  \[
8583	    \Gamma\bigl(V,\, \operatorname{pushPullObj}\mathcal{F}\,(\operatorname{Over.mk}
8584	      j_\sigma)\bigr)
8585	      \;\cong\;
8586	    \Gamma\bigl(U_\sigma \cap V,\, \mathcal{F}\bigr).
8587	  \]
8588	\end{lemma}
8589	\begin{proof}
8590	  \uses{lem:pushforward_obj_obj_mathlib, lem:restrictFunctorIsoPullback_mathlib,
8591	    lem:restrict_obj_mathlib}
8592	  This follows from three standard identifications. First, the leg is
8593	  \((j_\sigma)_*\,(j_\sigma)^*\mathcal{F}\); pushforward sections are computed by preimage,
8594	  \(\Gamma\bigl(V, (j_\sigma)_* N\bigr) = \Gamma\bigl(j_\sigma^{-1}(V), N\bigr)\)
8595	  (Lemma~\ref{lem:pushforward_obj_obj_mathlib}, an equality), applied with \(N =
8596	  (j_\sigma)^*\mathcal{F}\). Second, pullback along the open immersion \(j_\sigma\) is the
8597	  restriction functor: \((j_\sigma)^*\mathcal{F} \cong \mathcal{F}.\operatorname{restrict}
8598	  j_\sigma\) by Lemma~\ref{lem:restrictFunctorIsoPullback_mathlib}. Third, the sections of a
8599	  restricted module over \(j_\sigma^{-1}(V)\) are the sections of \(\mathcal{F}\) over the
8600	  image open (Lemma~\ref{lem:restrict_obj_mathlib}, an equality): \(\Gamma\bigl(j_\sigma^{-1}
8601	  (V), \mathcal{F}.\operatorname{restrict} j_\sigma\bigr) = \Gamma\bigl(j_\sigma\bigl(
8602	  j_\sigma^{-1}(V)\bigr), \mathcal{F}\bigr) = \Gamma\bigl(U_\sigma \cap V, \mathcal{F}\bigr)\),
8603	  the last equality because the image of the preimage of \(V\) under the open immersion
8604	  \(j_\sigma : U_\sigma \hookrightarrow X\) is exactly \(U_\sigma \cap V\). Composing the
8605	  three gives the stated isomorphism.
8606	\end{proof}
